begin;
create table if not exists public.document_analyses (id uuid primary key default gen_random_uuid(),upload_id uuid not null unique references public.client_uploaded_documents(id) on delete cascade,client_id uuid references public.admin_clients(id) on delete set null,status text not null default 'pending' check(status in ('pending','processing','completed','failed','manual_review')),detected_type text,suggested_name text,suggested_category text,summary text,extracted_text text,extracted_fields jsonb not null default '{}'::jsonb,confidence numeric(5,2),model text,error_message text,reviewed_at timestamptz,reviewed_by uuid references public.staff_members(id) on delete set null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.appointment_automation_settings (id text primary key default 'default',payment_policy text not null default 'full' check(payment_policy in ('full','deposit','optional')),deposit_percent integer not null default 50 check(deposit_percent between 1 and 100),reminder_offsets_hours integer[] not null default array[72,24,2],require_confirmation boolean not null default false,auto_cancel_unconfirmed boolean not null default false,cancellation_deadline_hours integer not null default 24 check(cancellation_deadline_hours between 1 and 336),email_enabled boolean not null default true,sms_enabled boolean not null default false,whatsapp_enabled boolean not null default false,updated_by text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.appointment_reminder_deliveries (id uuid primary key default gen_random_uuid(),appointment_id uuid not null references public.client_appointments(id) on delete cascade,offset_hours integer not null,channel text not null default 'email' check(channel in ('email','sms','whatsapp')),status text not null default 'pending' check(status in ('pending','sent','failed','skipped')),sent_at timestamptz,error_message text,created_at timestamptz not null default now(),unique(appointment_id,offset_hours,channel));
create index if not exists document_analyses_client_idx on public.document_analyses(client_id,created_at desc); create index if not exists reminder_deliveries_status_idx on public.appointment_reminder_deliveries(status,created_at desc);
alter table public.document_analyses enable row level security; alter table public.appointment_automation_settings enable row level security; alter table public.appointment_reminder_deliveries enable row level security;
revoke all on public.document_analyses,public.appointment_automation_settings,public.appointment_reminder_deliveries from anon,authenticated; grant all on public.document_analyses,public.appointment_automation_settings,public.appointment_reminder_deliveries to service_role;
drop policy if exists service_role_document_analyses on public.document_analyses; create policy service_role_document_analyses on public.document_analyses for all to service_role using(true) with check(true);
drop policy if exists service_role_appointment_automation_settings on public.appointment_automation_settings; create policy service_role_appointment_automation_settings on public.appointment_automation_settings for all to service_role using(true) with check(true);
drop policy if exists service_role_appointment_reminder_deliveries on public.appointment_reminder_deliveries; create policy service_role_appointment_reminder_deliveries on public.appointment_reminder_deliveries for all to service_role using(true) with check(true);
insert into public.appointment_automation_settings(id) values('default') on conflict(id) do nothing;
commit;
